var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"마지막까지 그 정도의 힘을 아껴두고 허를 찌르다니. 제법 머리를 썼구나.","JPN":"最後までこれほどの力を温存し隙を狙うとは、随分知恵を絞ったようだな。","ENG":"To think you conserved that much strength until the very end just to catch me off guard. Clever.","TWN":"在最後一刻，你竟然還能隱藏力量，偷襲我。你還挺有心計。"},"stage":{"bg":"BLACKMOUNTAIN_1","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"허나 바라밀 명도조차 꺾지 못한 본좌를 한낱 이 몸의 작은 조각이 무슨 수로 꺾을까.","JPN":"だが、波羅蜜命刀ですら倒れなかった吾輩を、欠片ごときが如何にして倒すというのだ。","ENG":"But what could a mere fragment like you possibly do to defeat me, when even the Sword of Paramita failed?","TWN":"但連波羅密命刀都無法擊敗的本座，你這個區區身體的一小部分，能用什麼來擊敗？"},"stage":{"bg":"BLACKMOUNTAIN_1","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"본좌는 이제 이 기워 붙인 껍데기 따윈 벗어던지고 새로운 마왕의 육신을 얻으리라.","JPN":"吾輩はこの継ぎ接ぎの皮を脱ぎ捨て、新たな魔王の肉体を手に入れよう。","ENG":"Now I shall cast off this stitched-together shell and claim my true form as Demon Lord.","TWN":"本座現在要拋棄這具縫補的外殼，獲得新的魔王之身。"},"stage":{"bg":"BLACKMOUNTAIN_1","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BLACKMOUNTAIN_1","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"그전에 마지막으로… 본좌의 작은 조각인 너를 삼켜, 다시 거두어주마.","JPN":"その前に、今ここで……吾輩の小さな欠片であるお前を呑み込み、回収してやろう。","ENG":"But before that… I'll devour you, fragment of mine, and reclaim you fully.","TWN":"在這之前，最後… 本座將吞噬你，這個本座的一小部分，再次收回。"},"stage":{"bg":"MS_1501_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"이 뱃속에서 네 여인과 그 못 다한 연을 매듭짓거라.","JPN":"吾輩の腹の底で、お前の女と果たせなかった想いを遂げるといい。","ENG":"Settle what remains of your pitiful bond with your woman inside this belly.","TWN":"就在我的肚子裡，與你的女人，為那未了的緣分畫下句點吧。"},"stage":{"bg":"MS_1501_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"허억…!","JPN":"はあっ……！","ENG":"*Gasp…!*","TWN":"啊…！"},"stage":{"bg":"HANOK_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"깜짝이야.","JPN":"びっくりした。","ENG":"Whoa.","TWN":"嚇我一跳。"},"stage":{"bg":"HANOK_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_HATE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"왜 그렇게 식은 땀을 흘려? 악몽이라도 꾼 거야?","JPN":"どうしたの？　そんなに冷や汗かいて……悪夢でも見た？","ENG":"Why are you covered in cold sweat? Had a nightmare?","TWN":"你為什麼流這麼多冷汗？做惡夢了嗎？"},"stage":{"bg":"HANOK_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_HATE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"연화…?","JPN":"レンカ……？","ENG":"Yeonhwa…?","TWN":"蓮華…？"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…뭐야. 그 죽은 사람 쳐다보는 듯한 눈빛은.","JPN":"……何よ、お化けでも見たような顔して。","ENG":"…What's with that look? Like you've seen a ghost.","TWN":"…什麼啊。你那是什麼看著死人的眼神。"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"밥 차렸으니까 얼른 일어나서 먹기나 해.","JPN":"ご飯できたから、早く起きなさい。","ENG":"Food is ready. Come eat already.","TWN":"飯做好了，快起來吃飯。"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이건? 계란찜?","JPN":"これは？　茶碗蒸し？","ENG":"This is… steamed egg?","TWN":"這是？蒸蛋？"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"왜? 당신이 제일 좋아하잖아. 아니야?","JPN":"何？　あなたの好物でしょう？　違った？","ENG":"What? It's your favorite, isn't it?","TWN":"怎麼了？你不是最喜歡嗎？不對嗎？"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…싫어하는 건 아닐세. 다만…","JPN":"……そうではない。ただ……","ENG":"…I don't dislike it. It's just that…","TWN":"…不是不喜歡。只是…"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그대가 나를 위해 요리를 해주는 것이 흔한 일은 아니니까.","JPN":"そなたが某に料理を作ってくれるのは、そうそうあることではないゆえ。","ENG":"You cooking for me isn't exactly common.","TWN":"你為我做飯這種事，並不常見。"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"별 수 없잖아. 당신은 늦잠을 자고, 난 배가 고픈데, 내 끼니만 챙길 순 없으니까.","JPN":"仕方ないじゃない。お腹空いたのにあなたはまだ寝てるし、自分だけ食べるわけにはいかないもの。","ENG":"What choice did I have? You overslept, and I was hungry. And I couldn't make just mine.","TWN":"沒辦法啊。你睡懶覺，我又肚子餓，我不能只顧自己啊。"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"맛은 어때? 간은 괜찮아?","JPN":"味はどう？　塩加減は？","ENG":"So, how is it? Did I season it right?","TWN":"好吃嗎？味道還行嗎？"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…조금 싱겁군.","JPN":"……少し薄いな。","ENG":"…A little bland.","TWN":"…有點淡。"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"흥, 다신 안 만들어줄래.","JPN":"ふん、二度と作ってやらないんだから。","ENG":"Hmph, fine. I won't make it again.","TWN":"哼，我再也不給你做了。"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그래도 좋다네. 그대가 차려주는 따뜻한 밥상을 싫어할 남자가 있겠나.","JPN":"それでも美味い。そなたが作ってくれる料理を拒む男などいるものか。","ENG":"It's still good. What man could dislike a warm meal made by you?","TWN":"這樣也很好。有哪個男人會不喜歡你做的熱騰騰飯菜呢。"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…뭐야. 이제 와서 그런 말 한다고 봐줄 줄 알고?","JPN":"……何よ、今更おだてても遅いからね。","ENG":"…Huh? You think sweet-talking me now will get you off the hook?","TWN":"…什麼啊。你以為現在說這種話，我就會原諒你嗎？"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"내일부턴 일찍 일어나겠다고 약속하지. 그땐 아침밥도 함께 준비하고. ","JPN":"明日からは早起きすると約束しよう。朝飯も一緒に作ろう。","ENG":"I promise I'll wake up early from now on. We'll make breakfast together next time.","TWN":"我保證明天會早點起床。到時候我們一起做早飯。"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};